import{_ as t,o as a,c as r,aQ as o}from"./chunks/framework.cDvftfeu.js";const c=JSON.parse('{"title":"开发者","description":"Ham开发者项目和文档概览。","frontmatter":{"description":"Ham开发者项目和文档概览。","next":{"text":"Ham互联概述","link":"/developers/open-platform/"}},"headers":[],"relativePath":"developers/index.md","filePath":"developers/index.md","lastUpdated":1777525243000}'),d={name:"developers/index.md"};function n(s,e,h,l,i,m){return a(),r("div",null,[...e[0]||(e[0]=[o('<h1 id="开发者" tabindex="-1">开发者 <a class="header-anchor" href="#开发者" aria-label="Permalink to &quot;开发者&quot;">​</a></h1><p>欢迎来到 Ham 开发者文档！Ham 目前包含以下项目：</p><table tabindex="0"><thead><tr><th>项目</th><th>说明</th><th>仓库</th></tr></thead><tbody><tr><td><a href="/developers/open-platform/">Ham互联</a></td><td>开放平台 OAuth 2.0 授权服务</td><td>—</td></tr><tr><td><a href="/developers/ham-web/">Ham Web</a></td><td>Web 前端，SSO 单点登录授权</td><td><a href="https://github.com/whu-ham/ham-web" target="_blank" rel="noreferrer">GitHub</a></td></tr><tr><td><a href="/developers/ham-rn/">Ham React Native组件</a></td><td>React Native 组件仓库，以 OTA 热更新集成到原生应用</td><td><a href="https://github.com/whu-ham/ham-rn" target="_blank" rel="noreferrer">GitHub</a></td></tr></tbody></table><h2 id="项目概览" tabindex="-1">项目概览 <a class="header-anchor" href="#项目概览" aria-label="Permalink to &quot;项目概览&quot;">​</a></h2><p><strong>Ham互联</strong> 是 Ham 开放平台提供的 OAuth 2.0 授权服务，允许第三方应用安全地获取 Ham 用户的授权信息，实现&quot;使用 Ham 登录&quot;功能。</p><p><strong>Ham Web</strong> 是 Ham 的 Web 前端项目，基于 Next.js 构建，主要承载 SSO 单点登录授权流程（包括二维码登录、Passkey 登录等），并作为 Ham 互联平台的 Web 端入口。</p><p><strong>Ham React Native组件</strong> 是 Ham 应用的 React Native 组件仓库，以 OTA 热更新的方式集成到原生应用中。它负责教务系统的课程查询、成绩查询、绩点计算、CAS 认证等核心功能的 UI 与业务逻辑。</p><h2 id="参与贡献" tabindex="-1">参与贡献 <a class="header-anchor" href="#参与贡献" aria-label="Permalink to &quot;参与贡献&quot;">​</a></h2><p>开源项目均采用 <a href="https://opensource.org/licenses/MIT" target="_blank" rel="noreferrer">MIT 许可证</a>，欢迎社区贡献。请在提交 PR 前阅读各项目的贡献指南。</p>',9)])])}const b=t(d,[["render",n]]);e